using namespace std;
int main() {
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
			if(i!=n/2){
				cout<<"|";
				for(int k=0;k<n-2;k++){
					cout<<"a";
				}cout<<"|"<<endl;
			}else{
				cout<<"|";
				for(int k=0;k<n-2;k++){
				cout<<"-";
				}cout<<"|"<<endl;
			}
			
		}
	}
